import React, { useState } from 'react';

const App = () => {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [category, setCategory] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log(title, content, category);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 rounded-md">
        <form onSubmit={handleSubmit}>
          <input className="block rounded-md px-4 py-2 mb-4 w-1/2" type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Title"/>
          <textarea className="block rounded-md px-4 py-2 mb-4 w-1/2" value={content} onChange={(e) => setContent(e.target.value)} placeholder="Content"/>
          <select className="block rounded-md px-4 py-2 mb-4 w-1/2" value={category} onChange={(e) => setCategory(e.target.value)}>
            <option value="">-- Select --</option>
            <option value="Category 1">Category 1</option>
            <option value="Category 2">Category 2</option>
          </select>
          <button className="bg-[#411C56] text-white rounded-md px-4 py-2 w-1/2" type="submit" onClick={handleSubmit}>Submit</button>
        </form>
      </div>
    </div>
  );
};

export default App;
